import React, { useState } from 'react';

const App = () => {
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(100);
  const categories = ['Electronics', 'Fashion', 'Home & Kitchen'];

  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
    const filtered = products.filter((product) => product.category === category);
    setFilteredProducts(filtered);
  };

  const handlePriceChange = (price) => {
    if (price === 'min') {
      setMinPrice(0);
    } else if (price === 'max') {
      setMaxPrice(100);
    } else {
      const [min, max] = price.split('-');
      setMinPrice(min);
      setMaxPrice(max);
    }
    const filtered = products.filter((product) => product.price >= minPrice && product.price <= maxPrice);
    setFilteredProducts(filtered);
  };

  const products = [
    { id: 1, name: 'Product 1', category: 'Electronics', price: 20 },
    { id: 2, name: 'Product 2', category: 'Fashion', price: 30 },
    // Add more products...
  ];

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white rounded-lg p-4 w-full max-w-sm">
        <h2 className="text-lg font-bold mb-4">Product Recommendations</h2>
        <div className="flex flex-wrap -mx-1 mb-4">
          {categories.map((category) => (
            <div key={category} className="w-full md:w-1/2 xl:w-1/3 p-1 md:p-4">
              <button
                className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded"
                onClick={() => handleCategoryChange(category)}
              >{category}</button>
            </div>
          ))}
        </div>
        <div className="flex flex-wrap -mx-1 mb-4">
          <div className="w-full md:w-1/2 xl:w-1/3 p-1 md:p-4">
            <input
              type="range"
              min="0"
              max="100"
              value="20"
              className="w-full h-2 bg-gray-200 appearance-none rounded"
              onChange={(e) => handlePriceChange(`20-${e.target.value}`)}
            />
            <span className="text-sm text-gray-400">Minimum price: {minPrice}</span>
          </div>
          <div className="w-full md:w-1/2 xl:w-1/3 p-1 md:p-4">
            <input
              type="range"
              min="0"
              max="100"
              value="80"
              className="w-full h-2 bg-gray-200 appearance-none rounded"
              onChange={(e) => handlePriceChange(`80-${e.target.value}`)}
            />
            <span className="text-sm text-gray-400">Maximum price: {maxPrice}</span>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Product</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Price</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredProducts.map((product) => (
                <tr key={product.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{product.name}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{product.category}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">${product.price}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default App;
